def validate_foreman_handoff(foreman_output: str) -> list[dict]:
    """Type guard: parse Foreman JSON and validate task structure."""
    try:
        data = json.loads(foreman_output)
    except json.JSONDecodeError:
        raise HandoffError("Foreman output is not valid JSON")

    tasks = data.get("tasks", [])
    for i, task in enumerate(tasks):
        if "role" not in task or "instruction" not in task:
            raise HandoffError(f"Task {i}: missing 'role' or 'instruction'")
        if task["role"] not in AVAILABLE_ROLES:
            raise HandoffError(f"Task {i}: unknown role '{task['role']}'")
    return tasks
```

